# shapes.spy - Core shape abstractions and implementations

from colors import Color, Point

interface IShape:
    def area(self) -> float: ...
    def perimeter(self) -> float: ...

interface IDrawable:
    def draw(self) -> str: ...

@abstract
class Shape(IShape, IDrawable):
    color: Color
    position: Point

    def __init__(self, color: Color, position: Point):
        self.color = color
        self.position = position

    @abstract
    def describe(self) -> str: ...

class Circle(Shape):
    radius: float

    def __init__(self, radius: float, color: Color, position: Point):
        super().__init__(color, position)
        self.radius = radius

    @override
    def area(self) -> float:
        pi: float = 3.14159
        return pi * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        pi: float = 3.14159
        return 2.0 * pi * self.radius

    @override
    def draw(self) -> str:
        return f"Drawing circle of radius {self.radius} at ({self.position.x}, {self.position.y})"

    @override
    def describe(self) -> str:
        return f"Circle(r={self.radius}, color={self.color})"

class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, width: float, height: float, color: Color, position: Point):
        super().__init__(color, position)
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    @override
    def draw(self) -> str:
        return f"Drawing rectangle {self.width}x{self.height} at ({self.position.x}, {self.position.y})"

    @override
    def describe(self) -> str:
        return f"Rectangle({self.width}x{self.height}, color={self.color})"

class Triangle(Shape):
    side_a: float
    side_b: float
    side_c: float

    def __init__(self, a: float, b: float, c: float, color: Color, position: Point):
        super().__init__(color, position)
        self.side_a = a
        self.side_b = b
        self.side_c = c

    @override
    def area(self) -> float:
        # Heron's formula
        s: float = (self.side_a + self.side_b + self.side_c) / 2.0
        return (s * (s - self.side_a) * (s - self.side_b) * (s - self.side_c)) ** 0.5

    @override
    def perimeter(self) -> float:
        return self.side_a + self.side_b + self.side_c

    @override
    def draw(self) -> str:
        return f"Drawing triangle at ({self.position.x}, {self.position.y})"

    @override
    def describe(self) -> str:
        return f"Triangle({self.side_a}, {self.side_b}, {self.side_c}, color={self.color})"

