# utils.spy - Utility functions and collection manager

from shapes import IShape, Shape, Circle, Rectangle
from colors import Color, Point, ColorPalette

class ShapeCollector:
    shapes: list[IShape]
    total_created: int = 0

    def __init__(self):
        self.shapes = []

    def add(self, shape: IShape) -> None:
        self.shapes.append(shape)
        ShapeCollector.total_created = ShapeCollector.total_created + 1

    def get_total_area(self) -> float:
        total: float = 0.0
        for shape in self.shapes:
            total = total + shape.area()
        return total

    def get_total_perimeter(self) -> float:
        total: float = 0.0
        for shape in self.shapes:
            total = total + shape.perimeter()
        return total

    def describe_all(self) -> str:
        descriptions: list[str] = []
        for shape in self.shapes:
            descriptions.append(shape.describe())
        return ", ".join(descriptions)

def create_random_shape(index: int, color: Color, pos: Point) -> Shape:
    if index % 3 == 0:
        return Circle(5.0, color, pos)
    elif index % 3 == 1:
        return Rectangle(4.0, 6.0, color, pos)
    else:
        return Triangle(3.0, 4.0, 5.0, color, pos)

def format_number(value: float, decimals: int) -> str:
    # Simple formatting helper
    factor: float = 10.0 ** decimals
    rounded: float = round(value * factor) / factor
    return str(rounded)
